def _record_usage(span, usage: Any) -> None:
    """Set OpenInference token-count attributes from a usage dict/object (#203)."""
    if not usage:
        return

    def g(key: str):
        return usage.get(key) if isinstance(usage, dict) else getattr(usage, key, None)

    prompt_toks = g("input_tokens")
    completion_toks = g("output_tokens")
    # Anthropic/Agent-SDK report cache tokens in SEPARATE fields excluded from
    # input_tokens; on a cached-prefix run they can dominate real input. Fold them
    # into the prompt/total counts (and emit the OpenInference cache slots) so
    # llm.token_count.total reflects all tokens processed, not an undercount on the
    # very tier where usage visibility matters most (#280). Real spend is still
    # tracked separately via llm.cost_usd.
    cache_read = g("cache_read_input_tokens")
    cache_write = g("cache_creation_input_tokens")
    if cache_read is not None:
        span.set_attribute("llm.token_count.prompt_details.cache_read", cache_read)
    if cache_write is not None:
        span.set_attribute("llm.token_count.prompt_details.cache_write", cache_write)

    prompt_total = None
    if prompt_toks is not None or cache_read is not None or cache_write is not None:
        prompt_total = (prompt_toks or 0) + (cache_read or 0) + (cache_write or 0)
        span.set_attribute("llm.token_count.prompt", prompt_total)
    if completion_toks is not None:
        span.set_attribute("llm.token_count.completion", completion_toks)
    if prompt_total is not None and completion_toks is not None:
        span.set_attribute("llm.token_count.total", prompt_total + completion_toks)

def test_record_usage_folds_cache_tokens_into_total():
    # #280: cache_read/creation tokens are part of input consumption but reported
    # in separate fields; the recorded total must include them, not undercount.
    class _Span:
        def __init__(self):
            self.attrs = {}

        def set_attribute(self, k, v):
            self.attrs[k] = v

    span = _Span()
    rc._record_usage(span, {
        "input_tokens": 100,
        "output_tokens": 20,
        "cache_read_input_tokens": 500,
        "cache_creation_input_tokens": 30,
    })
    assert span.attrs["llm.token_count.prompt_details.cache_read"] == 500
    assert span.attrs["llm.token_count.prompt_details.cache_write"] == 30
    assert span.attrs["llm.token_count.prompt"] == 100 + 500 + 30
    assert span.attrs["llm.token_count.completion"] == 20
    assert span.attrs["llm.token_count.total"] == 100 + 500 + 30 + 20

